int romanToInt(char* s) {
    int ans = nums(s[strlen(s) - 1]);
    for (int i = 0; i < (int) strlen(s) - 1; ++i) {
        int sign = nums(s[i]) < nums(s[i + 1]) ? -1 : 1;
        ans += sign * nums(s[i]);
    }
    return ans;
}
